      out.write("\r\n");
      out.write("    <!-- Our Story / Mission Section -->\r\n");
      out.write("    <h2 style=\"text-align: center; margin: 2rem 0;\"><i class=\"fas fa-bullseye\" style=\"color: var(--accent); margin-right: 10px;\"></i> Our Mission</h2>\r\n");
      out.write("    <div class=\"mission-grid\">\r\n");
