      out.write("          <i class=\"fas fa-exclamation-triangle\" style=\"color: var(--accent); margin-right: 8px;\"></i>\r\n");
      out.write("          <strong>Educational inequality</strong> is one of the most pressing challenges facing communities today.\r\n");
      out.write("          Millions of students are held back not by a lack of ability, but simply by a lack of access to basic\r\n");
      out.write("          learning materials — E-Books, Software & Apps, Digital Lab Tools, Educational Videos, and Templates & Guides.\r\n");
      out.write("        </p>\r\n");
      out.write("        <p style=\"line-height: 1.8; color: #555; margin-top: 1rem;\">\r\n");
      out.write("          <i class=\"fas fa-hand-holding-heart\" style=\"color: var(--primary); margin-right: 8px;\"></i>\r\n");
      out.write("          <strong>EduAid</strong> was created to tackle this problem directly. By building a trusted, community-driven\r\n");
      out.write("          platform, we connect those who have spare educational resources with students and teachers who need them most.\r\n");
      out.write("        </p>\r\n");
