      out.write("  // Intersection observer for fade-in animations\r\n");
      out.write("  const fadeElements = document.querySelectorAll('.fade-in');\r\n");
      out.write("\r\n");
      out.write("  const observer = new IntersectionObserver((entries) => {\r\n");
      out.write("    entries.forEach(entry => {\r\n");
      out.write("      if (entry.isIntersecting) {\r\n");
      out.write("        entry.target.style.opacity = '1';\r\n");
      out.write("        entry.target.style.transform = 'translateY(0)';\r\n");
      out.write("        observer.unobserve(entry.target);\r\n");
      out.write("      }\r\n");
      out.write("    });\r\n");
      out.write("  }, { threshold: 0.1 });\r\n");
      out.write("\r\n");
      out.write("  fadeElements.forEach(el => {\r\n");
      out.write("    el.style.opacity = '0';\r\n");
      out.write("    el.style.transform = 'translateY(30px)';\r\n");
      out.write("    el.style.transition = 'all 0.6s ease-out';\r\n");
      out.write("    observer.observe(el);\r\n");
      out.write("  });\r\n");
      out.write("</script>\r\n");
